"use client";

import { useEffect, useState } from "react";
import axios from "axios";
import LeetCodeRing from "@/src/components/leetcodeRing";

export default function Dashboard() {
  const [stats, setStats] = useState<any>(null);

  useEffect(() => {
    axios.get("/api/leetcode-stats").then((res) => {
      if (res.data.success) {
        setStats(res.data.data);
      }
    });
  }, []);

  if (!stats)
    return (
      <div className="min-h-screen bg-[#0f0f0f] text-white p-10">
        Loading...
      </div>
    );

  return (
    <div className="min-h-screen bg-[#0f0f0f] text-white p-10">

      <div className="grid grid-cols-4 gap-8">

        {/* LEFT SIDEBAR */}
        <div className="bg-[#1a1a1a] p-6 rounded-xl col-span-1 space-y-6">

          <div className="w-20 h-20 bg-gray-600 rounded-full mx-auto"></div>

          <div className="text-center">
            <h2 className="text-xl font-semibold">{stats.username}</h2>
            <p className="text-gray-400">Rank {stats.ranking}</p>
          </div>

          <div className="text-center">
            <p className="text-green-400 text-lg">
              {stats.totalSolved} Problems Solved
            </p>
          </div>

          <a
            href={`https://leetcode.com/${stats.username}`}
            target="_blank"
            className="block text-center bg-green-600 hover:bg-green-700 rounded-lg py-2"
          >
            View LeetCode Profile
          </a>
        </div>

        {/* RIGHT MAIN SECTION */}
        <div className="col-span-3 space-y-6">

          <LeetCodeRing
            totalSolved={stats.totalSolved}
            easy={stats.easy}
            medium={stats.medium}
            hard={stats.hard}
          />

          <div className="grid grid-cols-3 gap-6">
            <div className="bg-[#1a1a1a] p-6 rounded-xl text-green-400">
              Easy: {stats.easy}
            </div>
            <div className="bg-[#1a1a1a] p-6 rounded-xl text-yellow-400">
              Medium: {stats.medium}
            </div>
            <div className="bg-[#1a1a1a] p-6 rounded-xl text-red-500">
              Hard: {stats.hard}
            </div>
          </div>

        </div>
      </div>
    </div>
  );
}
